import { useState } from "react";
import { useNavigate } from "react-router-dom";
import API, { getApiError } from "../services/api";
import { PLAN_OPTIONS, formatDisplayDate, getPlanEndDate } from "../utils/membership";

const initialForm = {
  fullName: "",
  phone: "",
  age: "",
  plan: PLAN_OPTIONS[0],
  amountPaid: ""
};

export default function AddCustomer() {
  const navigate = useNavigate();
  const [form, setForm] = useState(initialForm);
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);

  const previewEndDate = getPlanEndDate(
    new Date().toISOString().split("T")[0],
    form.plan
  );

  const updateField = (key, value) => {
    setForm((current) => ({ ...current, [key]: value }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError("");

    if (!form.fullName || !form.phone || !form.age || !form.amountPaid) {
      setError("Please fill in name, phone, age, and amount paid before saving.");
      return;
    }

    setSaving(true);

    try {
      await API.post("/customers", {
        ...form,
        age: Number(form.age),
        amountPaid: Number(form.amountPaid)
      });

      navigate("/customers", {
        state: { message: `${form.fullName} was added successfully.` }
      });
    } catch (requestError) {
      setError(getApiError(requestError, "Unable to add this customer."));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="page-stack">
      <section className="page-heading">
        <div>
          <span className="eyebrow">New membership</span>
          <h2>Add a customer</h2>
          <p>
            Save member details once and the backend will assign the ID, start
            date, end date, and active status automatically.
          </p>
        </div>
      </section>

      <section className="form-layout">
        <form className="panel-card form-card" onSubmit={handleSubmit}>
          <div className="panel-card__header">
            <h3>Member details</h3>
          </div>

          {error ? <div className="status-banner status-banner--error">{error}</div> : null}

          <div className="form-grid">
            <label className="field">
              <span>Full name</span>
              <input
                placeholder="Enter member name"
                value={form.fullName}
                onChange={(event) => updateField("fullName", event.target.value)}
              />
            </label>

            <label className="field">
              <span>Phone number</span>
              <input
                placeholder="Enter phone number"
                value={form.phone}
                onChange={(event) => updateField("phone", event.target.value)}
              />
            </label>

            <label className="field">
              <span>Age</span>
              <input
                type="number"
                min="1"
                placeholder="Enter age"
                value={form.age}
                onChange={(event) => updateField("age", event.target.value)}
              />
            </label>

            <label className="field">
              <span>Amount paid</span>
              <input
                type="number"
                min="0"
                placeholder="Enter amount paid"
                value={form.amountPaid}
                onChange={(event) => updateField("amountPaid", event.target.value)}
              />
            </label>
          </div>

          <label className="field">
            <span>Membership plan</span>
            <select
              value={form.plan}
              onChange={(event) => updateField("plan", event.target.value)}
            >
              {PLAN_OPTIONS.map((plan) => (
                <option key={plan} value={plan}>
                  {plan}
                </option>
              ))}
            </select>
          </label>

          <div className="form-actions">
            <button className="button" type="submit" disabled={saving}>
              {saving ? "Saving..." : "Create customer"}
            </button>
            <button
              className="button button--ghost"
              type="button"
              onClick={() => setForm(initialForm)}
            >
              Reset form
            </button>
          </div>
        </form>

        <aside className="panel-card info-card">
          <div className="panel-card__header">
            <h3>Membership preview</h3>
          </div>

          <div className="info-card__row">
            <span>Selected plan</span>
            <strong>{form.plan}</strong>
          </div>
          <div className="info-card__row">
            <span>Starts on</span>
            <strong>{formatDisplayDate(new Date().toISOString().split("T")[0])}</strong>
          </div>
          <div className="info-card__row">
            <span>Expected end date</span>
            <strong>{formatDisplayDate(previewEndDate)}</strong>
          </div>

          <p className="panel-note">
            This preview mirrors the current membership plan rules so the add
            flow stays consistent when we swap from mock data to the real API.
          </p>
        </aside>
      </section>
    </div>
  );
}
